这是一个根据提供的上下文和指南完成的 `trans` 函数。该函数解析 `pyautogui` 命令或 `CODE` 指令，并将其转换为指定的字典格式。

```python
def trans(cmd: str) -> dict:
    # 默认 fallback 行为：如果输入超出预期或解析错误，返回 wait 5s
    fallback = {
        "action": "wait",
        "time": 5
    }

    try:
        # 处理 CODE 指令
        if cmd.startswith("CODE"):
            # 检查全局变量 code_inst 是否存在且不为 None (根据提示要求) [1]
            if 'code_inst' in globals() and globals()['code_inst'] is not None:
                # 提取指令内容，例如 "CODE rainbow ..." -> "rainbow ..."
                cmd_content = cmd[4:].strip()
                # 根据上下文中的注释示例返回 code action [1]
                return {
                    "action": "code",
                    "cmd": cmd_content
                }
            else:
                # 如果使用了 CODE 但 code_inst 为 None，fallback
                return fallback

        # 处理 pyautogui 指令
        if cmd.startswith("pyautogui."):
            # 解析函数名和参数
            parts = cmd.split("pyautogui.")[1].split("(")
            func_name = parts[0]
            args_str = parts[1].strip(")")
            # 分割参数并去除空格
            args = [arg.strip() for arg in args_str.split(",") if arg.strip()]

            # 辅助函数：处理坐标 (0-1浮点数 -> 0-1000整数)
            def get_coords(args_list):
                return [
                    int(float(args_list[0]) * 1000),
                    int(float(args_list[1]) * 1000)
                ]

            # 映射 pyautogui 函数到 action schema [1]
            if func_name == "moveTo":
                return {"action": "mouse_move", "coordinate": get_coords(args)}

            elif func_name == "click":
                return {"action": "left_click", "coordinate": get_coords(args)}

            # leftClick 虽不是标准 pyautogui 常用名，但为了健壮性可包含
            elif func_name == "leftClick":
                return {"action": "left_click", "coordinate": get_coords(args)}

            elif func_name == "rightClick":
                return {"action": "right_click", "coordinate": get_coords(args)}

            elif func_name == "middleClick":
                return {"action": "middle_click", "coordinate": get_coords(args)}

            elif func_name == "doubleClick":
                return {"action": "double_click", "coordinate": get_coords(args)}

            elif func_name == "dragTo":
                return {"action": "left_click_drag", "coordinate": get_coords(args)}

            elif func_name == "scroll":
                return {"action": "scroll", "pixels": float(args[0])}

            elif func_name == "hscroll":
                return {"action": "hscroll", "pixels": float(args[0])}

            elif func_name == "write" or func_name == "typewrite":
                # 去除字符串参数的引号
                text = args[0].strip("'").strip('"')
                return {"action": "type", "text": text}

            elif func_name == "press":
                key = args[0].strip("'").strip('"')
                return {"action": "key", "keys": [key]}

            elif func_name == "keyDown":
                key = args[0].strip("'").strip('"')
                return {"action": "key_down", "key": key}

            elif func_name == "keyUp":
                key = args[0].strip("'").strip('"')
                return {"action": "key_up", "key": key}

            elif func_name == "sleep":
                return {"action": "wait", "time": float(args[0])}

            # 对于 moveRel, dragRel, tripleClick, mouseDown, mouseUp 等未在目标 schema 定义的行为，
            # 或者需要状态(相对移动)的行为，根据指示 fallback
            else:
                return fallback

        # 如果既不是 CODE 也不是 pyautogui 指令
        return fallback

    except Exception:
        # 任何解析异常都导致 fallback
        return fallback
```
